PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE IF NOT EXISTS "django_migrations" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app" varchar(255) NOT NULL, "name" varchar(255) NOT NULL, "applied" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "auth_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "django_admin_log" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "object_id" text NULL, "object_repr" varchar(200) NOT NULL, "action_flag" smallint unsigned NOT NULL CHECK ("action_flag" >= 0), "change_message" text NOT NULL, "content_type_id" integer NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "action_time" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "django_content_type" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "app_label" varchar(100) NOT NULL, "model" varchar(100) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_permission" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "content_type_id" integer NOT NULL REFERENCES "django_content_type" ("id") DEFERRABLE INITIALLY DEFERRED, "codename" varchar(100) NOT NULL, "name" varchar(255) NOT NULL);
CREATE TABLE IF NOT EXISTS "auth_group" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(150) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "auth_user" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "username" varchar(150) NOT NULL UNIQUE, "last_name" varchar(150) NOT NULL, "email" varchar(254) NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "first_name" varchar(150) NOT NULL);
CREATE TABLE IF NOT EXISTS "django_session" ("session_key" varchar(40) NOT NULL PRIMARY KEY, "session_data" text NOT NULL, "expire_date" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "cart_cart_old" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "session_key" varchar(40) NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" integer NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "cart_cartitem" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "quantity" integer unsigned NOT NULL CHECK ("quantity" >= 0), "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "cart_id" bigint NOT NULL REFERENCES "cart_cart_old" ("id") DEFERRABLE INITIALLY DEFERRED, "product_id" bigint NOT NULL REFERENCES "products_product" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "orders_orderitem" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "quantity" integer unsigned NOT NULL CHECK ("quantity" >= 0), "unit_price" decimal NOT NULL, "subtotal" decimal NOT NULL, "order_id" bigint NOT NULL REFERENCES "orders_order" ("id") DEFERRABLE INITIALLY DEFERRED, "product_id" bigint NOT NULL REFERENCES "products_product" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "orders_order" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "order_number" varchar(32) NOT NULL UNIQUE, "status" varchar(20) NOT NULL, "subtotal" decimal NOT NULL, "shipping_cost" decimal NOT NULL, "tax_amount" decimal NOT NULL, "discount_amount" decimal NOT NULL, "full_name" varchar(255) NOT NULL, "email" varchar(254) NOT NULL, "city" varchar(100) NOT NULL, "paid_at" datetime NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" integer NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "address" text NOT NULL, "grand_total" decimal NOT NULL, "is_pickup" bool NOT NULL, "mpesa_checkout_id" varchar(100) NULL, "mpesa_receipt" varchar(100) NULL, "phone" varchar(20) NOT NULL, "payment_method" varchar(50) NOT NULL);
CREATE TABLE IF NOT EXISTS "products_category" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(100) NOT NULL UNIQUE, "created_at" datetime NOT NULL, "description" text NOT NULL, "is_active" bool NOT NULL, "updated_at" datetime NOT NULL, "slug" varchar(120) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "products_product" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL, "slug" varchar(255) NOT NULL UNIQUE, "price" decimal NOT NULL, "description" text NOT NULL, "key_features" text NOT NULL CHECK ((JSON_VALID("key_features") OR "key_features" IS NULL)), "specifications" text NOT NULL CHECK ((JSON_VALID("specifications") OR "specifications" IS NULL)), "image" varchar(100) NULL, "datasheet" varchar(100) NULL, "stock" integer unsigned NOT NULL CHECK ("stock" >= 0), "is_active" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "category_id" bigint NOT NULL REFERENCES "products_category" ("id") DEFERRABLE INITIALLY DEFERRED, "sku" varchar(64) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "blog_category" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(120) NOT NULL UNIQUE, "slug" varchar(50) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "blog_sourceorganization" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(255) NOT NULL, "website" varchar(200) NOT NULL, "rss_feed" varchar(200) NULL);
CREATE TABLE IF NOT EXISTS "blog_tag" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "name" varchar(80) NOT NULL UNIQUE, "slug" varchar(50) NOT NULL UNIQUE);
CREATE TABLE IF NOT EXISTS "blog_blogpost" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "title" varchar(255) NOT NULL, "slug" varchar(50) NOT NULL UNIQUE, "excerpt" text NOT NULL, "content" text NOT NULL, "source_url" varchar(200) NULL, "status" varchar(20) NOT NULL, "featured_image" varchar(100) NULL, "meta_title" varchar(255) NOT NULL, "meta_description" text NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "published_at" datetime NULL, "author_id" integer NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "category_id" bigint NULL REFERENCES "blog_category" ("id") DEFERRABLE INITIALLY DEFERRED, "source_id" bigint NULL REFERENCES "blog_sourceorganization" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "blog_blogpost_tags" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "blogpost_id" bigint NOT NULL REFERENCES "blog_blogpost" ("id") DEFERRABLE INITIALLY DEFERRED, "tag_id" bigint NOT NULL REFERENCES "blog_tag" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "blog_blogimage" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "image" varchar(100) NOT NULL, "caption" varchar(200) NOT NULL, "alt_text" varchar(200) NOT NULL, "order" integer unsigned NOT NULL CHECK ("order" >= 0), "is_featured" bool NOT NULL, "created_at" datetime NOT NULL, "blog_post_id" bigint NOT NULL REFERENCES "blog_blogpost" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "policies_policytemplate" ("id" char(32) NOT NULL PRIMARY KEY, "name" varchar(255) NOT NULL, "description" text NOT NULL, "content_structure" text NOT NULL CHECK ((JSON_VALID("content_structure") OR "content_structure" IS NULL)), "version" integer unsigned NOT NULL CHECK ("version" >= 0), "is_active" bool NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL);
CREATE TABLE IF NOT EXISTS "policies_policy" ("id" char(32) NOT NULL PRIMARY KEY, "title" varchar(255) NOT NULL, "slug" varchar(100) NOT NULL UNIQUE, "responses" text NOT NULL CHECK ((JSON_VALID("responses") OR "responses" IS NULL)), "generated_content" text NOT NULL, "status" varchar(20) NOT NULL, "effective_date" date NOT NULL, "pdf_file" varchar(100) NULL, "qr_code" varchar(100) NULL, "published_at" datetime NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" integer NOT NULL REFERENCES "auth_user" ("id") DEFERRABLE INITIALLY DEFERRED, "template_id" char(32) NULL REFERENCES "policies_policytemplate" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "accounts_user" ("password" varchar(128) NOT NULL, "last_login" datetime NULL, "is_superuser" bool NOT NULL, "is_staff" bool NOT NULL, "is_active" bool NOT NULL, "date_joined" datetime NOT NULL, "id" char(32) NOT NULL PRIMARY KEY, "email" varchar(254) NOT NULL UNIQUE, "username" varchar(150) NULL, "phone_number" varchar(15) NULL UNIQUE, "google_id" varchar(255) NULL UNIQUE, "facebook_id" varchar(255) NULL UNIQUE, "auth_provider" varchar(50) NOT NULL, "first_name" varchar(150) NOT NULL, "last_name" varchar(150) NOT NULL, "profile_photo" varchar(100) NULL, "company_name" varchar(255) NOT NULL, "business_type" varchar(50) NOT NULL, "kra_pin" varchar(50) NOT NULL, "business_reg" varchar(100) NOT NULL, "address" text NOT NULL, "city" varchar(100) NOT NULL, "county" varchar(100) NOT NULL, "postal_code" varchar(10) NOT NULL, "default_payment_method" varchar(20) NOT NULL, "default_mpesa_phone" varchar(15) NOT NULL, "auto_pay_enabled" bool NOT NULL, "auto_pay_threshold" decimal NULL, "billing_email" varchar(254) NOT NULL, "email_verified" bool NOT NULL, "phone_verified" bool NOT NULL, "verified_at" datetime NULL, "preferred_language" varchar(10) NOT NULL, "email_notifications" bool NOT NULL, "sms_notifications" bool NOT NULL, "marketing_consent" bool NOT NULL, "last_login_ip" char(39) NULL, "login_attempts" integer NOT NULL, "locked_until" datetime NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "last_active" datetime NULL);
CREATE TABLE IF NOT EXISTS "accounts_user_groups" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" char(32) NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "group_id" integer NOT NULL REFERENCES "auth_group" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "accounts_user_user_permissions" ("id" integer NOT NULL PRIMARY KEY AUTOINCREMENT, "user_id" char(32) NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED, "permission_id" integer NOT NULL REFERENCES "auth_permission" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "accounts_userdevice" ("id" char(32) NOT NULL PRIMARY KEY, "device_id" varchar(255) NOT NULL, "device_name" varchar(255) NOT NULL, "device_type" varchar(50) NOT NULL, "user_agent" text NOT NULL, "ip_address" char(39) NOT NULL, "location_city" varchar(100) NOT NULL, "location_country" varchar(100) NOT NULL, "is_trusted" bool NOT NULL, "last_login" datetime NOT NULL, "created_at" datetime NOT NULL, "user_id" char(32) NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "accounts_userloginhistory" ("id" char(32) NOT NULL PRIMARY KEY, "login_time" datetime NOT NULL, "ip_address" char(39) NOT NULL, "user_agent" text NOT NULL, "device_id" varchar(255) NOT NULL, "successful" bool NOT NULL, "failure_reason" varchar(255) NOT NULL, "user_id" char(32) NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "accounts_userpaymentmethod" ("id" char(32) NOT NULL PRIMARY KEY, "method_type" varchar(20) NOT NULL, "mpesa_phone" varchar(15) NOT NULL, "mpesa_verified" bool NOT NULL, "mpesa_verified_at" datetime NULL, "card_last4" varchar(4) NOT NULL, "card_brand" varchar(50) NOT NULL, "card_expiry" varchar(7) NOT NULL, "wallet_address" varchar(255) NOT NULL, "display_name" varchar(100) NOT NULL, "is_default" bool NOT NULL, "is_active" bool NOT NULL, "last_used" datetime NULL, "used_count" integer NOT NULL, "created_at" datetime NOT NULL, "updated_at" datetime NOT NULL, "user_id" char(32) NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "accounts_usertransaction" ("id" char(32) NOT NULL PRIMARY KEY, "service" varchar(20) NOT NULL, "service_ref" varchar(100) NOT NULL, "amount" decimal NOT NULL, "mpesa_receipt" varchar(100) NOT NULL, "mpesa_checkout_id" varchar(100) NOT NULL, "status" varchar(20) NOT NULL, "created_at" datetime NOT NULL, "completed_at" datetime NULL, "payment_method_id" char(32) NULL REFERENCES "accounts_userpaymentmethod" ("id") DEFERRABLE INITIALLY DEFERRED, "user_id" char(32) NOT NULL REFERENCES "accounts_user" ("id") DEFERRABLE INITIALLY DEFERRED);
CREATE TABLE IF NOT EXISTS "tools_tool" ("id" char(32) NOT NULL PRIMARY KEY, "name" varchar(200) NOT NULL, "slug" varchar(50) NOT NULL UNIQUE, "description" text NOT NULL, "icon" varchar(100) NOT NULL, "is_active" bool NOT NULL, "order" integer unsigned NOT NULL CHECK ("order" >= 0), "created_at" datetime NOT NULL, "is_free" bool NOT NULL, "price" decimal NULL, "stripe_price_id" varchar(100) NOT NULL, "updated_at" datetime NOT NULL, "url" varchar(500) NOT NULL);
