INSERT INTO products_category VALUES(1,'fire-safety-equipment','2026-02-27 02:24:06.936838','Essential fire prevention and emergency response equipment including extinguishers, alarms, and suppression tools designed to enhance workplace and institutional safety compliance.',1,'2026-03-01 14:14:02.442053','fire-safety-equipment');
INSERT INTO products_product VALUES(1,'Swinging Type Fire Hose Reel','swinging-type-fire-hose-reel',2,replace(replace('<p>The High-Performance Swinging Fire Hose Reel (180° Pivot Type) is engineered for rapid and efficient fire response in commercial, industrial, and institutional environments. The 180-degree swinging arm design allows flexible deployment in any direction, minimizing hose kinking and ensuring uninterrupted water flow during emergencies.</p>\r\n\r\n<p>Constructed from heavy-duty mild steel with a flame-red epoxy polyester powder coating, the reel offers superior corrosion resistance and long-term durability. The internal waterways are made from brass to prevent rust formation and guarantee reliable performance.</p>\r\n\r\n<p>The system comes pre-fitted with a 30-meter UV-protected high-pressure hose available in 19mm (¾") or 25mm (1") diameters. An adjustable jet/spray nozzle enables quick switching between a focused jet stream and a protective spray pattern for enhanced firefighting control.</p>\r\n\r\n<p>Fully compliant with KEBS requirements and conforming to EN 671-1 standards, this hose reel is ideal for Class A fire risks in schools, hotels, warehouses, factories, shopping centers, and office buildings.</p>','\r',char(13)),'\n',char(10)),'["180\u00b0 swinging arm design for flexible hose deployment", "KEBS certified", "Compliant with EN 671-1 standard", "Corrosion-resistant epoxy polyester powder coating", "Brass internal waterways to prevent rust", "30-meter high-pressure hose (19mm or 25mm options)", "Adjustable jet/spray nozzle", "UV-protected side discs", "Maximum working pressure: 12 bar", "5-year warranty"]','{"Hose Length": "30 meters", "Hose Diameter": "19mm (3/4 inch) or 25mm (1 inch)", "Drum Diameter": "550mm \u2013 560mm", "Maximum Working Pressure": "12 Bar", "Test Pressure": "18 Bar", "Minimum Flow Rate": "34 L/min at 4 Bar", "Weight (with hose)": "Approximately 19.5kg \u2013 22kg", "Dimensions": "Approx. 560mm (W) x 560mm (H) x 220mm (D)", "Drum Material": "Mild Steel", "Internal Waterway Material": "Brass", "Hose Material": "PVC/Rubber Reinforced"}','products/images/2026/02/swinging-type-fire-hose-reel_.jpg','products/datasheets/2026/02/swinging-type-fire-hose-reel_.jpg',25,1,'2026-02-27 02:40:25.608186','2026-02-27 08:03:19.565937',1,'FS-EXT-6KG');
INSERT INTO products_product VALUES(2,'ABC Dry Powder Fire Extinguisher – 1kg','abc-dry-powder-fire-extinguisher-1kg',2500,replace(replace('<h1>1kg ABC Dry Powder Fire Extinguisher – BS EN3 & CE Approved (PG1A)</h1>\r\n\r\n<p>The <strong>1kg ABC Dry Powder Fire Extinguisher</strong> is a compact, multi-purpose fire suppression solution designed for vehicles, homes, offices, retail shops, and small commercial spaces in Kenya. Engineered to meet <strong>BS EN3 standards</strong> and manufactured under <strong>ISO 9001 quality management systems</strong>, this extinguisher delivers reliable performance in emergency fire situations.</p>\r\n\r\n<p>This <strong>ABC fire extinguisher</strong> is effective against <strong>Class A (solid combustibles), Class B (flammable liquids), Class C (gases), and live electrical fires</strong>, making it one of the most versatile fire safety tools available. Its dry chemical powder rapidly interrupts the fire’s chemical reaction, ensuring fast knockdown and suppression.</p>\r\n\r\n<p>Designed with an easy-to-read <strong>pressure gauge</strong>, corrosion-resistant cylinder, and impact-resistant handle, this 1kg unit is ideal for vehicles, small offices, apartments, and security posts. Each unit is leak-tested before packaging to guarantee safety and compliance.</p>\r\n\r\n<h2>Why Choose This 1kg Fire Extinguisher?</h2>\r\n<ul>\r\n<li>Compact and lightweight – perfect for vehicles and confined spaces</li>\r\n<li>BS EN3 approved and CE certified for quality assurance</li>\r\n<li>Reliable protection against electrical and flammable liquid fires</li>\r\n<li>Clear graphical instructions for quick emergency operation</li>\r\n<li>Suitable for Kenyan fire safety compliance requirements</li>\r\n</ul>\r\n\r\n<p><strong>Applications:</strong> Cars, taxis, trucks, homes, offices, schools, shops, and small business premises.</p>\r\n\r\n<p>Invest in dependable <strong>fire safety equipment in Kenya</strong> with this high-performance 1kg ABC Dry Powder Fire Extinguisher.</p>','\r',char(13)),'\n',char(10)),'["BS EN3 approved", "ISO 9001 certified manufacturing", "CE approved fire extinguisher", "ABC multi-purpose fire rating (Class A, B, C & electrical fires)", "Easy-to-read pressure gauge", "Rust and impact resistant handle", "Polyester powder-coated red cylinder (custom colors available)", "Leak-tested before packaging", "Compact design ideal for vehicles", "Clear graphical operating instructions"]','{"Product Name": "1kg ABC Dry Powder Fire Extinguisher", "Model": "PG1A", "Extinguishing Agent": "ABC Dry Chemical Powder (40%)", "Capacity": "1kg", "Fire Rating": "5A 34B C", "Working Pressure": "14 bar", "Test Pressure": "27 bar", "Operating Temperature Range": "-30\u00b0C to +60\u00b0C", "Cylinder Diameter": "85 mm", "Cylinder Length": "270 mm", "Volume": "1.25 L", "Full Weight": "2.4 kg", "Finish": "Polyester powder-coated (Red standard)", "Packing Size": "485 \u00d7 250 \u00d7 365 mm", "Units per Carton": "8 pcs", "Units per 20ft Container": "8000 pcs"}','products/images/2026/03/1KG_Dry_Powder_Fire_Extinguisher__ABC_Fire_Protection_mehit.app.jpg','',10,1,'2026-03-01 14:32:47.351493','2026-03-01 14:32:47.351551',1,'FS-EXT-1KG-ABC');
