INSERT INTO policies_policytemplate VALUES('42f026b88c7d4103aa9e12a907cce7ac','Nema Model','policy','{"html": "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"UTF-8\">\n  <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n  <title>Privacy Policy \u00b7 mehit.app</title>\n  <!-- Font Awesome + Google Font Inter (same as questionnaire) -->\n  <link rel=\"stylesheet\" href=\"https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.4.0/css/all.min.css\">\n  <link href=\"https://fonts.googleapis.com/css2?family=Inter:opsz,wght@14..32,300..800&display=swap\" rel=\"stylesheet\">\n  <style>\n    /* --- mehit.app brand colours (exactly as questionnaire) --- */\n    * {\n      margin: 0;\n      padding: 0;\n      box-sizing: border-box;\n      font-family: ''Inter'', -apple-system, BlinkMacSystemFont, ''Segoe UI'', Roboto, sans-serif;\n    }\n    :root {\n      --primary: #004aad;\n      --primary-dark: #003080;\n      --primary-light: #3a7bd5;\n      --accent: #27ae60;\n      --accent-light: #6fcf97;\n      --danger: #e74c3c;\n      --warning: #f39c12;\n      --black: #111827;\n      --gray-dark: #374151;\n      --gray: #6b7280;\n      --gray-light: #9ca3af;\n      --border: #e5e7eb;\n      --bg-light: #f8f9fb;\n      --bg-white: #ffffff;\n      --shadow-sm: 0 1px 2px 0 rgba(0, 0, 0, 0.05);\n      --shadow-md: 0 4px 6px -1px rgba(0, 0, 0, 0.1);\n      --shadow-lg: 0 10px 15px -3px rgba(0, 0, 0, 0.1);\n      --radius: 0.5rem;\n    }\n    body {\n      background: var(--bg-white);\n      color: var(--black);\n      line-height: 1.6;\n      padding: 2rem 1.5rem;\n      max-width: 1100px;\n      margin: 0 auto;\n    }\n    .policy-header {\n      margin-bottom: 2.5rem;\n      border-bottom: 2px solid var(--accent);\n      padding-bottom: 1.5rem;\n    }\n    .logo {\n      display: flex;\n      align-items: center;\n      gap: 0.75rem;\n      font-weight: 800;\n      font-size: 1.8rem;\n      color: var(--primary);\n      text-decoration: none;\n    }\n    .logo-icon {\n      color: var(--accent);\n      font-size: 2rem;\n    }\n    .last-updated {\n      color: var(--gray);\n      font-size: 0.95rem;\n      margin-top: 0.5rem;\n    }\n    h1 {\n      font-size: 2rem;\n      font-weight: 700;\n      color: var(--primary-dark);\n      margin: 1.5rem 0 0.5rem;\n    }\n    h2 {\n      font-size: 1.5rem;\n      font-weight: 600;\n      color: var(--primary);\n      margin: 2rem 0 1rem;\n      padding-bottom: 0.5rem;\n      border-bottom: 1px solid var(--border);\n    }\n    h3 {\n      font-size: 1.2rem;\n      font-weight: 600;\n      color: var(--gray-dark);\n      margin: 1.5rem 0 0.75rem;\n    }\n    p, li {\n      color: var(--gray-dark);\n      margin-bottom: 0.75rem;\n    }\n    ul, ol {\n      margin-left: 1.5rem;\n      margin-bottom: 1.5rem;\n    }\n    li {\n      margin-bottom: 0.4rem;\n    }\n    a {\n      color: var(--primary);\n      text-decoration: none;\n      font-weight: 500;\n    }\n    a:hover {\n      text-decoration: underline;\n    }\n    .highlight-box {\n      background: var(--bg-light);\n      border-left: 4px solid var(--accent);\n      padding: 1rem 1.5rem;\n      margin: 1.5rem 0;\n      border-radius: 0 var(--radius) var(--radius) 0;\n    }\n    .contact-details {\n      background: var(--bg-light);\n      padding: 1.2rem 1.5rem;\n      border-radius: var(--radius);\n      margin-top: 1rem;\n    }\n    hr {\n      border: none;\n      border-top: 1px solid var(--border);\n      margin: 2rem 0;\n    }\n    .footer-note {\n      font-size: 0.85rem;\n      color: var(--gray-light);\n      text-align: center;\n      margin-top: 3rem;\n      border-top: 1px solid var(--border);\n      padding-top: 1.5rem;\n    }\n    /* print-friendly */\n    @media print {\n      body { padding: 0.5in; }\n    }\n    table {\n      width: 100%;\n      border-collapse: collapse;\n      margin: 1rem 0;\n    }\n    th, td {\n      border: 1px solid var(--border);\n      padding: 0.75rem;\n      text-align: left;\n      vertical-align: top;\n    }\n    th {\n      background: var(--bg-light);\n      font-weight: 600;\n    }\n  </style>\n</head>\n<body>\n  <div class=\"policy-header\">\n    <div class=\"logo\">\n      <i class=\"fas fa-shield-alt logo-icon\"></i>\n      <span>mehit.app</span>\n    </div>\n    <h1>Privacy Policy</h1>\n    <div class=\"last-updated\">\n      <strong>Effective Date:</strong> {{ effective_date }}<br>\n      <strong>Last Updated:</strong> {{ last_updated }}<br>\n      <strong>Version:</strong> {{ policy_version }}\n    </div>\n  </div>\n\n  <!-- ==================== 1. INTRODUCTION ==================== -->\n  <h2>1. Introduction</h2>\n  <p>{{ company_name }} (\"we\", \"us\", \"our\") is committed to protecting your privacy and ensuring that your personal data is handled in a safe and responsible manner. This Privacy Policy explains how we collect, use, disclose, and safeguard your information when you visit our website <a href=\"{{ website_url }}\">{{ website_url }}</a>, use our mobile application {% if app_name %}\u201c{{ app_name }}\u201d{% else %}[app name]{% endif %}, or engage with our services.</p>\n  <p>We comply with the <strong>Kenya Data Protection Act, 2019</strong> (the \"Act\") and the relevant regulations issued by the Office of the Data Protection Commissioner (ODPC). Please read this policy carefully to understand our views and practices regarding your personal data.</p>\n\n  <!-- ==================== 2. WHO WE ARE ==================== -->\n  <h2>2. Who We Are</h2>\n  <div class=\"highlight-box\">\n    <p><strong>Company Name:</strong> {{ company_name }}<br>\n    {% if business_reg %}<strong>Registration Number:</strong> {{ business_reg }}<br>{% endif %}\n    <strong>Physical Address:</strong> {{ physical_address }}<br>\n    <strong>Postal Address:</strong> {{ postal_address }}<br>\n    <strong>Email:</strong> <a href=\"mailto:{{ contact_email }}\">{{ contact_email }}</a><br>\n    <strong>Phone:</strong> {{ contact_phone }}<br>\n    <strong>Website:</strong> <a href=\"{{ website_url }}\">{{ website_url }}</a><br>\n    <strong>Mobile App:</strong> {{ app_name|default:\"[Not applicable]\" }}</p>\n    <p>We are the <strong>data controller</strong> (as defined in the Act) for the purposes of your personal data.</p>\n  </div>\n\n  <!-- ==================== 3. WHAT PERSONAL DATA WE COLLECT ==================== -->\n  <h2>3. What Personal Data We Collect</h2>\n  <p>We may collect, use, store and transfer different kinds of personal data about you. We have grouped these as follows:</p>\n\n  <h3>3.1 Categories of personal data</h3>\n  <ul>\n    <li><strong>Identity Data:</strong> full name, username or similar identifier, marital status, title, date of birth, gender, national ID number, passport number, KRA PIN, NSSF, NHIF, or other government-issued identifiers.</li>\n    <li><strong>Contact Data:</strong> billing address, delivery address, email address, telephone numbers, and emergency contact details.</li>\n    <li><strong>Financial Data:</strong> bank account details, M\u2011PESA transaction records, payment card information, income details, credit history, and credit reference bureau reports.</li>\n    <li><strong>Technical Data:</strong> internet protocol (IP) address, login data, browser type and version, time zone setting and location, browser plug\u2011in types and versions, operating system and platform, and other technology on the devices you use to access our services.</li>\n    <li><strong>Profile Data:</strong> your username and password, purchases or orders made by you, your interests, preferences, feedback and survey responses.</li>\n    <li><strong>Usage Data:</strong> information about how you use our website, products and services, including your browsing patterns, clickstream data, and interactions with our content.</li>\n    <li><strong>Marketing and Communications Data:</strong> your preferences in receiving marketing from us and our third parties, and your communication preferences.</li>\n    <li><strong>Sensitive Data:</strong> (where applicable) health information, genetic or biometric data, religious or philosophical beliefs, political opinions, trade union membership, sexual orientation, criminal records, or children\u2019s data. We only process sensitive data where we have obtained your explicit consent, or where it is necessary for legal, employment, or social security obligations.</li>\n  </ul>\n\n  <h3>3.2 Special categories (if you are a minor)</h3>\n  <p>If you are under 18 years of age, we will obtain parental or guardian consent before collecting your personal data. Parents/guardians may exercise the rights set out in Section 10 on behalf of the child.</p>\n\n  <!-- ==================== 4. HOW WE COLLECT YOUR PERSONAL DATA ==================== -->\n  <h2>4. How We Collect Your Personal Data</h2>\n  <p>We use different methods to collect data from and about you, including:</p>\n  <ul>\n    <li><strong>Direct interactions:</strong> You may give us your Identity, Contact, and Financial Data by filling in forms, corresponding with us by phone, email, SMS, or otherwise. This includes personal data you provide when you:\n      <ul>\n        <li>apply for our products or services;</li>\n        <li>create an account on our website or app;</li>\n        <li>subscribe to our newsletter or other publications;</li>\n        <li>request marketing to be sent to you;</li>\n        <li>enter a competition, promotion or survey; or</li>\n        <li>give us feedback or contact us.</li>\n      </ul>\n    </li>\n    <li><strong>Automated technologies or interactions:</strong> As you interact with our website or app, we may automatically collect Technical Data about your equipment, browsing actions and patterns. We collect this personal data by using cookies, server logs, and other similar technologies. Please see our <a href=\"#\">Cookie Policy</a> for further details.</li>\n    <li><strong>Third parties or publicly available sources:</strong> We may receive personal data about you from various third parties and public sources, such as:\n      <ul>\n        <li>Public registries (e.g., eCitizen, Companies Registry, land registry);</li>\n        <li>Credit reference bureaus (CRBs) for credit checks;</li>\n        <li>Partner organisations that you have authorised to share your information;</li>\n        <li>Social media platforms (if you interact with our pages);</li>\n        <li>Data brokers or aggregators;</li>\n        <li>Government agencies (where legally required).</li>\n      </ul>\n    </li>\n  </ul>\n\n  <!-- ==================== 5. HOW WE USE YOUR PERSONAL DATA ==================== -->\n  <h2>5. How We Use Your Personal Data</h2>\n  <p>We will only use your personal data when the law allows us to. Most commonly, we will use your personal data in the following circumstances:</p>\n  <table>\n    <thead>\n      <tr>\n        <th>Purpose/Activity</th>\n        <th>Type of data</th>\n        <th>Lawful basis for processing including basis of legitimate interest</th>\n      </tr>\n    </thead>\n    <tbody>\n      <tr>\n        <td>To register you as a new customer</td>\n        <td>(a) Identity<br>(b) Contact</td>\n        <td>Performance of a contract with you</td>\n      </tr>\n      <tr>\n        <td>To process and deliver your order including: (a) Manage payments, fees and charges (b) Collect and recover money owed to us</td>\n        <td>(a) Identity<br>(b) Contact<br>(c) Financial<br>(d) Transaction<br>(e) Marketing and Communications</td>\n        <td>(a) Performance of a contract with you<br>(b) Necessary for our legitimate interests (to recover debts due to us)</td>\n      </tr>\n      <tr>\n        <td>To manage our relationship with you which will include: (a) Notifying you about changes to our terms or privacy policy (b) Asking you to leave a review or take a survey</td>\n        <td>(a) Identity<br>(b) Contact<br>(c) Profile<br>(d) Marketing and Communications</td>\n        <td>(a) Performance of a contract with you<br>(b) Necessary to comply with a legal obligation<br>(c) Necessary for our legitimate interests (to keep our records updated and to study how customers use our products/services)</td>\n      </tr>\n      <tr>\n        <td>To enable you to partake in a prize draw, competition or complete a survey</td>\n        <td>(a) Identity<br>(b) Contact<br>(c) Profile<br>(d) Usage<br>(e) Marketing and Communications</td>\n        <td>(a) Performance of a contract with you<br>(b) Necessary for our legitimate interests (to study how customers use our products/services, to develop them and grow our business)</td>\n      </tr>\n      <tr>\n        <td>To administer and protect our business and this website (including troubleshooting, data analysis, testing, system maintenance, support, reporting and hosting of data)</td>\n        <td>(a) Identity<br>(b) Contact<br>(c) Technical</td>\n        <td>(a) Necessary for our legitimate interests (for running our business, provision of administration and IT services, network security, to prevent fraud)<br>(b) Necessary to comply with a legal obligation</td>\n      </tr>\n      <tr>\n        <td>To deliver relevant website content and advertisements to you and measure or understand the effectiveness of the advertising we serve to you</td>\n        <td>(a) Identity<br>(b) Contact<br>(c) Profile<br>(d) Usage<br>(e) Marketing and Communications<br>(f) Technical</td>\n        <td>Necessary for our legitimate interests (to study how customers use our products/services, to develop them, to grow our business and to inform our marketing strategy)</td>\n      </tr>\n      <tr>\n        <td>To use data analytics to improve our website, products/services, marketing, customer relationships and experiences</td>\n        <td>(a) Technical<br>(b) Usage</td>\n        <td>Necessary for our legitimate interests (to define types of customers for our products and services, to keep our website updated and relevant, to develop our business and to inform our marketing strategy)</td>\n      </tr>\n      <tr>\n        <td>To make suggestions and recommendations to you about goods or services that may be of interest to you</td>\n        <td>(a) Identity<br>(b) Contact<br>(c) Technical<br>(d) Usage<br>(e) Profile</td>\n        <td>Necessary for our legitimate interests (to develop our products/services and grow our business)</td>\n      </tr>\n    </tbody>\n  </table>\n\n  <h3>5.1 Sensitive data</h3>\n  <p>If we process any sensitive personal data (as listed in section 3.1), we will obtain your explicit consent before doing so, unless another legal basis applies (e.g., legal obligation, vital interests). You have the right to withdraw consent at any time.</p>\n\n  <h3>5.2 Automated decision-making</h3>\n  <p>{{ automated_decision_making|default:\"We do not currently use automated decision-making (including profiling) for credit scoring, fraud detection, or personalised marketing. If this changes, we will update this policy and, where required, obtain your consent.\" }}</p>\n\n  <!-- ==================== 6. COOKIES AND TRACKING TECHNOLOGIES ==================== -->\n  <h2>6. Cookies and Tracking Technologies</h2>\n  <p>Our website and app use cookies and similar tracking technologies (such as pixels, SDKs, and local storage) to distinguish you from other users. This helps us provide you with a good experience when you browse and also allows us to improve our site.</p>\n  <p>We use the following types of cookies:</p>\n  <ul>\n    <li><strong>Strictly necessary cookies:</strong> Required for the website to function (e.g., login, shopping cart).</li>\n    <li><strong>Functional cookies:</strong> Remember your preferences and choices.</li>\n    <li><strong>Performance/analytics cookies:</strong> Help us understand how visitors interact with our site.</li>\n    <li><strong>Targeting/advertising cookies:</strong> Deliver relevant ads and measure campaign effectiveness.</li>\n  </ul>\n  <p>You can set your browser to refuse all or some browser cookies, or to alert you when websites set or access cookies. If you disable or refuse cookies, please note that some parts of this website may become inaccessible or not function properly.</p>\n  <p>For more detailed information, see our <a href=\"#\">Cookie Policy</a>.</p>\n\n  <!-- ==================== 7. DISCLOSURES OF YOUR PERSONAL DATA ==================== -->\n  <h2>7. Disclosures of Your Personal Data</h2>\n  <p>We may share your personal data with the following categories of third parties for the purposes set out in Section 5:</p>\n  <ul>\n    <li>Service providers acting as processors who provide IT, system administration, cloud storage, payment processing, marketing, analytics, and other services.</li>\n    <li>Credit reference bureaus for the purpose of assessing your credit score and verifying your identity.</li>\n    <li>Debt collectors in the event of default.</li>\n    <li>Government authorities, regulators, or law enforcement where required by law, court order, or to protect our rights.</li>\n    <li>Professional advisers including lawyers, bankers, auditors and insurers who provide consultancy, banking, legal, insurance and accounting services.</li>\n    <li>Business partners, suppliers and sub\u2011contractors for the performance of any contract we enter into with them or you.</li>\n    <li>Third parties to whom we may choose to sell, transfer, or merge parts of our business or our assets. Alternatively, we may seek to acquire other businesses or merge with them. If a change happens to our business, then the new owners may use your personal data in the same way as set out in this privacy policy.</li>\n  </ul>\n  <p>We require all third parties to respect the security of your personal data and to treat it in accordance with the law. We do not allow our third\u2011party service providers to use your personal data for their own purposes and only permit them to process your personal data for specified purposes and in accordance with our instructions.</p>\n\n  <!-- ==================== 8. INTERNATIONAL TRANSFERS ==================== -->\n  <h2>8. International Transfers</h2>\n  <p>{{ international_transfers|default:\"We do not currently transfer your personal data outside Kenya. If this changes, we will ensure appropriate safeguards are in place, such as standard contractual clauses approved by the ODPC, and update this policy accordingly.\" }}</p>\n\n  <!-- ==================== 9. DATA SECURITY ==================== -->\n  <h2>9. Data Security</h2>\n  <p>We have put in place appropriate security measures to prevent your personal data from being accidentally lost, used or accessed in an unauthorised way, altered or disclosed. In addition, we limit access to your personal data to those employees, agents, contractors and other third parties who have a business need to know. They will only process your personal data on our instructions and they are subject to a duty of confidentiality.</p>\n  <p>We have put in place procedures to deal with any suspected personal data breach and will notify you and any applicable regulator (including the ODPC) of a breach where we are legally required to do so.</p>\n  <p>Our security measures include:</p>\n  <ul>\n    <li>Encryption of data at rest and in transit (TLS/SSL).</li>\n    <li>Two\u2011factor authentication for administrative access.</li>\n    <li>Firewalls, intrusion detection systems, and regular security patching.</li>\n    <li>Regular backups and disaster recovery procedures.</li>\n    <li>Staff training on data protection and confidentiality agreements.</li>\n  </ul>\n\n  <!-- ==================== 10. DATA RETENTION ==================== -->\n  <h2>10. Data Retention</h2>\n  <p>We will only retain your personal data for as long as reasonably necessary to fulfil the purposes we collected it for, including for the purposes of satisfying any legal, regulatory, tax, accounting or reporting requirements. We may retain your personal data for a longer period in the event of a complaint or if we reasonably believe there is a prospect of litigation in respect to our relationship with you.</p>\n  <p>To determine the appropriate retention period for personal data, we consider the amount, nature, and sensitivity of the personal data, the potential risk of harm from unauthorised use or disclosure, the purposes for which we process your personal data and whether we can achieve those purposes through other means, and the applicable legal requirements.</p>\n  <p>Examples of retention periods:</p>\n  <ul>\n    <li><strong>Customer data:</strong> While your account is active, plus {{ retention_customer|default:\"[X]\" }} years after last interaction to handle any queries or claims.</li>\n    <li><strong>Employee data:</strong> {{ retention_employee|default:\"[X]\" }} years after termination of employment, as required by labour laws.</li>\n    <li><strong>Financial records:</strong> 7 years (as required by the Tax Procedures Act).</li>\n    <li><strong>Website analytics data:</strong> 26 months (Google Analytics default).</li>\n  </ul>\n  <p>In some circumstances you can ask us to delete your data: see Section 11 below for further information.</p>\n\n  <!-- ==================== 11. YOUR LEGAL RIGHTS ==================== -->\n  <h2>11. Your Legal Rights</h2>\n  <p>Under the Kenya Data Protection Act, you have the following rights regarding your personal data:</p>\n  <ul>\n    <li><strong>Right to be informed</strong> \u2013 you have the right to be provided with clear, transparent and easily understandable information about how we use your personal data and your rights. This is why we are providing you with this policy.</li>\n    <li><strong>Right of access</strong> \u2013 you have the right to obtain confirmation that your personal data is being processed and request a copy of the personal data we hold about you.</li>\n    <li><strong>Right to rectification</strong> \u2013 you are entitled to have your personal data corrected if it is inaccurate or incomplete.</li>\n    <li><strong>Right to erasure (right to be forgotten)</strong> \u2013 you can request us to delete or remove your personal data in certain circumstances, such as where it is no longer necessary for the purpose we collected it, you withdraw consent, or you object and we have no overriding legitimate ground.</li>\n    <li><strong>Right to restrict processing</strong> \u2013 you have the right to ask us to suspend the processing of your personal data in certain situations, for example if you want us to establish its accuracy or the reason for processing it.</li>\n    <li><strong>Right to data portability</strong> \u2013 you have the right to ask us to provide your personal data to you in a structured, commonly used and machine\u2011readable format, and to transmit that data to another data controller.</li>\n    <li><strong>Right to object</strong> \u2013 you have the right to object to processing based on our legitimate interests (including profiling) or for direct marketing purposes.</li>\n    <li><strong>Rights in relation to automated decision\u2011making and profiling</strong> \u2013 you have the right not to be subject to a decision based solely on automated processing which produces legal effects or similarly significantly affects you.</li>\n  </ul>\n  <p>If you wish to exercise any of these rights, please contact us using the details in Section 13. We will respond to your request within the timelines set by the Act (generally 7 days for access, 14 days for rectification/erasure). There is no charge for exercising your rights, unless your request is manifestly unfounded or excessive.</p>\n\n  <!-- ==================== 12. CHANGES TO THIS PRIVACY POLICY ==================== -->\n  <h2>12. Changes to This Privacy Policy</h2>\n  <p>We may update this Privacy Policy from time to time to reflect changes in our practices, legal requirements, or operational reasons. Any updated version will be posted on our website with a revised \"Last Updated\" date. We encourage you to review this policy periodically. In case of material changes, we will notify you by email or through a prominent notice on our website.</p>\n\n  <!-- ==================== 13. CONTACT US ==================== -->\n  <h2>13. Contact Us</h2>\n  <p>If you have any questions about this Privacy Policy or wish to exercise your rights, please contact our Data Protection Officer (DPO) using the details below:</p>\n  <div class=\"contact-details\">\n    <p><strong>Data Protection Officer</strong><br>\n    {{ dpo_name|default:\"[DPO Name]\" }}<br>\n    <strong>Email:</strong> <a href=\"mailto:{{ dpo_email }}\">{{ dpo_email }}</a><br>\n    <strong>Phone:</strong> {{ dpo_phone }}<br>\n    <strong>Postal Address:</strong> {{ dpo_postal }}<br>\n    <strong>Physical Address:</strong> {{ dpo_physical }}</p>\n  </div>\n  <p>You also have the right to lodge a complaint with the <strong>Office of the Data Protection Commissioner (ODPC)</strong> if you are not satisfied with our response:</p>\n  <p>\n    Office of the Data Protection Commissioner<br>\n    Email: <a href=\"mailto:complaints@odpc.go.ke\">complaints@odpc.go.ke</a><br>\n    Website: <a href=\"https://www.odpc.go.ke\" target=\"_blank\">www.odpc.go.ke</a><br>\n    Postal: P.O. Box 19426 \u2013 00102, Nairobi, Kenya.\n  </p>\n\n  <hr>\n  <div class=\"footer-note\">\n    \u00a9 {{ current_year }} {{ company_name }}. All rights reserved. Powered by mehit.app.\n  </div>\n</body>\n</html>\n"}',1,1,'2026-03-03 16:05:36.662081','2026-03-03 16:05:36.662121');
